1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no, viewport-fit=cover">
6	<meta name="apple-mobile-web-app-capable" content="yes">
7	<meta name="apple-mobile-web-app-status-bar-style" content="black-translucent">
8	<title>CYBER SNAKE // 赛博贪吃蛇</title>
9	<style>
10	  :root {
11	    --neon-cyan: #00f0ff;
12	    --neon-magenta: #ff00ff;
13	    --neon-gold: #ffaa00;
14	    --bg-deep: #050510;
15	    --glass-bg: rgba(10, 12, 30, 0.65);
16	    --glass-border: rgba(0, 240, 255, 0.18);
17	  }
18	
19	  * { margin: 0; padding: 0; box-sizing: border-box; }
20	
21	  html, body {
22	    width: 100%; height: 100%;
23	    overflow: hidden;
24	    background: var(--bg-deep);
25	    font-family: 'Courier New', 'Source Code Pro', 'Menlo', monospace;
26	    touch-action: none;
27	    -webkit-touch-callout: none;
28	    -webkit-user-select: none;
29	    user-select: none;
30	    -webkit-tap-highlight-color: transparent;
31	    position: fixed;
32	    top: 0; left: 0;
33	  }
34	
35	  /* ========== CANVAS LAYER ========== */
36	  #particle-canvas {
37	    position: fixed; top: 0; left: 0; z-index: 0;
38	    pointer-events: none;
39	  }
40	
41	  #game-canvas {
42	    position: fixed; z-index: 1;
43	    border-radius: 8px;
44	    box-shadow:
45	      0 0 30px rgba(0, 240, 255, 0.25),
46	      0 0 60px rgba(0, 240, 255, 0.08),
47	      inset 0 0 30px rgba(0, 240, 255, 0.04);
48	  }
49	
50	  /* ========== UI OVERLAY ========== */
51	  #ui-layer {
52	    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
53	    z-index: 10; pointer-events: none;
54	    display: flex; flex-direction: column;
55	    align-items: center; justify-content: flex-start;
56	    padding: env(safe-area-inset-top, 12px) 16px env(safe-area-inset-bottom, 16px) 16px;
57	  }
58	
59	  /* ---- Score pill ---- */
60	  #score-bar {
61	    pointer-events: auto;
62	    display: flex; align-items: center; gap: 10px;
63	    padding: 10px 20px;
64	    background: var(--glass-bg);
65	    backdrop-filter: blur(18px);
66	    -webkit-backdrop-filter: blur(18px);
67	    border: 1px solid var(--glass-border);
68	    border-radius: 40px;
69	    box-shadow: 0 4px 24px rgba(0,0,0,0.45);
70	    transition: opacity 0.3s;
71	  }
72	  #score-bar.hidden { opacity: 0; pointer-events: none; }
73	
74	  #avatar-thumb {
75	    width: 36px; height: 36px;
76	    border-radius: 50%;
77	    border: 2px solid var(--neon-cyan);
78	    box-shadow: 0 0 12px rgba(0,240,255,0.5);
79	    object-fit: cover;
80	    background: #0a0a1a;
81	  }
82	
83	  #score-text {
84	    color: #fff;
85	    font-size: 18px;
86	    font-weight: bold;
87	    letter-spacing: 2px;
88	    text-shadow: 0 0 10px var(--neon-cyan), 0 0 20px var(--neon-cyan);
89	    min-width: 60px; text-align: center;
90	  }
91	
92	  #high-score-text {
93	    color: rgba(255,255,255,0.5);
94	    font-size: 11px;
95	    letter-spacing: 1px;
96	  }
97	
98	  /* ---- Glass panels (start / game-over) ---- */
99	  .glass-panel {
100	    pointer-events: auto;
101	    display: flex; flex-direction: column; align-items: center;
102	    padding: 32px 28px;
103	    background: var(--glass-bg);
104	    backdrop-filter: blur(24px);
105	    -webkit-backdrop-filter: blur(24px);
106	    border: 1px solid var(--glass-border);
107	    border-radius: 20px;
108	    box-shadow: 0 8px 40px rgba(0,0,0,0.55), 0 0 40px rgba(0,240,255,0.06);
109	    text-align: center;
110	    transition: transform 0.35s cubic-bezier(0.34,1.56,0.64,1), opacity 0.3s;
111	  }
112	  .glass-panel.hidden {
113	    transform: scale(0.85);
114	    opacity: 0;
115	    pointer-events: none;
116	  }
117	
118	  .panel-title {
119	    font-size: 28px; font-weight: 900;
120	    letter-spacing: 4px;
121	    color: #fff;
122	    text-shadow: 0 0 14px var(--neon-cyan), 0 0 30px var(--neon-cyan), 0 0 60px var(--neon-cyan);
123	    margin-bottom: 4px;
124	  }
125	  .panel-subtitle {
126	    font-size: 13px; letter-spacing: 6px;
127	    color: var(--neon-magenta);
128	    text-shadow: 0 0 8px var(--neon-magenta);
129	    margin-bottom: 24px;
130	  }
131	
132	  .neon-btn {
133	    pointer-events: auto;
134	    display: inline-block;
135	    padding: 14px 42px;
136	    font-family: inherit; font-size: 16px; font-weight: bold;
137	    letter-spacing: 3px; text-transform: uppercase;
138	    color: #fff;
139	    background: rgba(0,240,255,0.08);
140	    border: 1.5px solid var(--neon-cyan);
141	    border-radius: 40px;
142	    cursor: pointer;
143	    text-shadow: 0 0 8px var(--neon-cyan);
144	    box-shadow: 0 0 18px rgba(0,240,255,0.2), inset 0 0 18px rgba(0,240,255,0.05);
145	    transition: all 0.25s;
146	    margin: 6px;
147	  }
148	  .neon-btn:active {
149	    background: rgba(0,240,255,0.2);
150	    box-shadow: 0 0 30px rgba(0,240,255,0.45), inset 0 0 24px rgba(0,240,255,0.12);
151	    transform: scale(0.95);
152	  }
153	  .neon-btn.magenta {
154	    border-color: var(--neon-magenta);
155	    text-shadow: 0 0 8px var(--neon-magenta);
156	    box-shadow: 0 0 18px rgba(255,0,255,0.2), inset 0 0 18px rgba(255,0,255,0.05);
157	  }
158	  .neon-btn.magenta:active {
159	    background: rgba(255,0,255,0.2);
160	    box-shadow: 0 0 30px rgba(255,0,255,0.45);
161	  }
162	
163	  .score-display {
164	    font-size: 52px; font-weight: 900;
165	    color: #fff;
166	    text-shadow: 0 0 12px var(--neon-gold), 0 0 30px var(--neon-gold);
167	    margin: 8px 0;
168	  }
169	  .score-label {
170	    font-size: 12px; letter-spacing: 3px;
171	    color: rgba(255,255,255,0.5);
172	  }
173	
174	  /* ---- Swipe hint ---- */
175	  #swipe-hint {
176	    position: fixed; bottom: 28px; left: 50%; transform: translateX(-50%);
177	    z-index: 8; pointer-events: none;
178	    color: rgba(255,255,255,0.35);
179	    font-size: 11px; letter-spacing: 2px;
180	    text-align: center;
181	    transition: opacity 0.6s;
182	  }
183	
184	  /* ---- Responsive ---- */
185	  @media (max-width: 380px) {
186	    .panel-title { font-size: 22px; letter-spacing: 2px; }
187	    .panel-subtitle { font-size: 11px; letter-spacing: 4px; }
188	    .neon-btn { padding: 12px 28px; font-size: 14px; }
189	    .score-display { font-size: 40px; }
190	  }
191	  @media (min-width: 768px) {
192	    .panel-title { font-size: 38px; }
193	    .score-display { font-size: 64px; }
194	  }
195	</style>
196	</head>
197	<body>
198	
199	<canvas id="particle-canvas"></canvas>
200	<canvas id="game-canvas"></canvas>
201	
202	<div id="ui-layer">
203	  <!-- Score bar (in-game) -->
204	  <div id="score-bar" class="hidden">
205	    <img id="avatar-thumb" src="IMG_7817.JPG" alt="head">
206	    <span id="score-text">000</span>
207	    <span id="high-score-text">BEST 000</span>
208	  </div>
209	
210	  <div style="flex:1; display:flex; align-items:center; justify-content:center;">
211	    <!-- Start screen -->
212	    <div id="start-panel" class="glass-panel">
213	      <div class="panel-title">CYBER SNAKE</div>
214	      <div class="panel-subtitle">赛 博 贪 吃 蛇</div>
215	      <button class="neon-btn" id="btn-start">START GAME</button>
216	      <div style="margin-top:12px;font-size:11px;color:rgba(255,255,255,0.3);letter-spacing:1px;">
217	        SWIPE TO CONTROL &nbsp;|&nbsp; EAT TO GROW
218	      </div>
219	    </div>
220	
221	    <!-- Game over screen -->
222	    <div id="over-panel" class="glass-panel hidden">
223	      <div class="panel-title" style="color:var(--neon-magenta);text-shadow:0 0 14px var(--neon-magenta),0 0 30px var(--neon-magenta);">GAME OVER</div>
224	      <div class="score-label">FINAL SCORE</div>
225	      <div class="score-display" id="final-score">0</div>
226	      <div class="score-label" style="margin-bottom:16px;">
227	        HIGH SCORE &nbsp;<span id="final-high">0</span>
228	      </div>
229	      <button class="neon-btn" id="btn-restart">PLAY AGAIN</button>
230	      <button class="neon-btn magenta" id="btn-share">SHARE SCORE</button>
231	    </div>
232	  </div>
233	</div>
234	
235	<div id="swipe-hint">↑↓←→ &nbsp;SWIPE ANYWHERE</div>
236	
237	<script>
238	// ======================================================================
239	//  CYBER SNAKE — 赛博朋克贪吃蛇  (mobile-first)
240	// ======================================================================
241	
242	// -------------------- CONFIG --------------------
243	const CONFIG = {
244	  GRID_TARGET:   18,       // target cells per row
245	  MIN_CELL:      16,       // minimum cell px
246	  BASE_SPEED:    140,      // ms per tick at start
247	  MIN_SPEED:     58,       // fastest tick
248	  SPEED_STEP:    3,        // ms faster per food
249	  INITIAL_LEN:   4,
250	  AVATAR_EVERY:  5,        // switch head every N foods
251	  PARTICLE_MAX:  70,
252	  SWIPE_MIN:     28,       // px
253	  SHAKE_MS:      280,      // shake duration
254	  GLOW_BLUR:     14,
255	};
256	
257	// -------------------- DOM REFS --------------------
258	const particleCanvas = document.getElementById('particle-canvas');
259	const pCtx = particleCanvas.getContext('2d');
260	const gameCanvas = document.getElementById('game-canvas');
261	const gCtx = gameCanvas.getContext('2d');
262	
263	const scoreBar    = document.getElementById('score-bar');
264	const avatarThumb = document.getElementById('avatar-thumb');
265	const scoreText   = document.getElementById('score-text');
266	const highScoreText = document.getElementById('high-score-text');
267	const startPanel  = document.getElementById('start-panel');
268	const overPanel   = document.getElementById('over-panel');
269	const finalScore  = document.getElementById('final-score');
270	const finalHigh   = document.getElementById('final-high');
271	const swipeHint   = document.getElementById('swipe-hint');
272	const btnStart    = document.getElementById('btn-start');
273	const btnRestart  = document.getElementById('btn-restart');
274	const btnShare    = document.getElementById('btn-share');
275	
276	// -------------------- HEAD IMAGES --------------------
277	const HEAD_PATHS = [
278	  'IMG_7817.JPG',
279	  'IMG_7818.PNG',
280	  'IMG_7819.PNG',
281	  'IMG_7820.PNG',
282	];
283	const headImages = [];    // loaded Image objects
284	let headQueue = [];       // shift/push cycle queue
285	let currentHeadImg = null;
286	let imagesLoaded = false;
287	
288	function loadImages() {
289	  let loaded = 0;
290	  return new Promise((resolve) => {
291	    HEAD_PATHS.forEach((src, i) => {
292	      const img = new Image();
293	      img.onload = () => {
294	        loaded++;
295	        if (loaded === HEAD_PATHS.length) {
296	          headQueue = [...headImages]; // copy for shift cycling
297	          currentHeadImg = headQueue[0];
298	          imagesLoaded = true;
299	          avatarThumb.src = currentHeadImg.src;
300	          resolve();
301	        }
302	      };
303	      img.onerror = () => {
304	        loaded++;
305	        if (loaded === HEAD_PATHS.length && headImages.length > 0) {
306	          headQueue = [...headImages];
307	          currentHeadImg = headQueue[0];
308	          imagesLoaded = true;
309	          resolve();
310	        }
311	      };
312	      headImages.push(img);
313	      img.src = src;
314	    });
315	  });
316	}
317	
318	function cycleHeadImage() {
319	  if (headQueue.length === 0) return;
320	  const used = headQueue.shift();   // remove first
321	  headQueue.push(used);             // push to end
322	  currentHeadImg = headQueue[0];    // new head
323	  avatarThumb.src = currentHeadImg.src;
324	}
325	
326	// -------------------- FOOD SPRITE (poop / 大便) --------------------
327	let foodSprite = null; // offscreen canvas
328	
329	function createFoodSprite(size) {
330	  const s = Math.max(size, 32);
331	  const c = document.createElement('canvas');
332	  c.width = s * 2; c.height = s * 2;
333	  const ctx = c.getContext('2d');
334	  const cx = s, cy = s, r = s * 0.78;
335	
336	  // Shadow
337	  ctx.shadowColor = 'rgba(0,0,0,0.4)';
338	  ctx.shadowBlur = r * 0.25;
339	  ctx.shadowOffsetY = r * 0.1;
340	
341	  // Main body — rounded bulbous shape
342	  const grad = ctx.createRadialGradient(cx - r*0.2, cy - r*0.25, r*0.1, cx, cy, r);
343	  grad.addColorStop(0, '#c08a5c');
344	  grad.addColorStop(0.45, '#8b5e3c');
345	  grad.addColorStop(0.8, '#5c3a1e');
346	  grad.addColorStop(1, '#3d2210');
347	  ctx.fillStyle = grad;
348	  ctx.beginPath();
349	  // Bottom ellipse
350	  ctx.ellipse(cx, cy + r*0.12, r*0.85, r*0.58, 0, 0, Math.PI*2);
351	  ctx.fill();
352	  // Main body
353	  ctx.beginPath();
354	  ctx.arc(cx, cy - r*0.05, r*0.72, 0, Math.PI*2);
355	  ctx.fill();
356	
357	  ctx.shadowColor = 'transparent';
358	  ctx.shadowBlur = 0;
359	  ctx.shadowOffsetY = 0;
360	
361	  // Top swirl — left bump
362	  ctx.fillStyle = '#a0724a';
363	  ctx.beginPath();
364	  ctx.arc(cx - r*0.32, cy - r*0.52, r*0.28, 0, Math.PI*2);
365	  ctx.fill();
366	  ctx.fillStyle = '#b8845e';
367	  ctx.beginPath();
368	  ctx.arc(cx - r*0.32, cy - r*0.55, r*0.2, 0, Math.PI*2);
369	  ctx.fill();
370	
371	  // Top swirl — right bump
372	  ctx.fillStyle = '#9a6d44';
373	  ctx.beginPath();
374	  ctx.arc(cx + r*0.34, cy - r*0.5, r*0.3, 0, Math.PI*2);
375	  ctx.fill();
376	  ctx.fillStyle = '#b28055';
377	  ctx.beginPath();
378	  ctx.arc(cx + r*0.34, cy - r*0.53, r*0.22, 0, Math.PI*2);
379	  ctx.fill();
380	
381	  // Center top highlight
382	  ctx.fillStyle = '#d4a878';
383	  ctx.beginPath();
384	  ctx.arc(cx + r*0.02, cy - r*0.48, r*0.14, 0, Math.PI*2);
385	  ctx.fill();
386	
387	  // Highlight shine
388	  const hl = ctx.createRadialGradient(cx - r*0.22, cy - r*0.38, r*0.02, cx, cy, r*0.9);
389	  hl.addColorStop(0, 'rgba(255,255,255,0.28)');
390	  hl.addColorStop(0.35, 'rgba(255,255,255,0.06)');
391	  hl.addColorStop(1, 'rgba(0,0,0,0)');
392	  ctx.fillStyle = hl;
393	  ctx.beginPath();
394	  ctx.arc(cx, cy, r*0.8, 0, Math.PI*2);
395	  ctx.fill();
396	
397	  // Eyes (small white dots for comedic effect)
398	  ctx.fillStyle = '#fff';
399	  ctx.beginPath();
400	  ctx.arc(cx - r*0.2, cy - r*0.3, r*0.08, 0, Math.PI*2);
401	  ctx.fill();
402	  ctx.beginPath();
403	  ctx.arc(cx + r*0.22, cy - r*0.3, r*0.08, 0, Math.PI*2);
404	  ctx.fill();
405	  ctx.fillStyle = '#111';
406	  ctx.beginPath();
407	  ctx.arc(cx - r*0.19, cy - r*0.3, r*0.04, 0, Math.PI*2);
408	  ctx.fill();
409	  ctx.beginPath();
410	  ctx.arc(cx + r*0.23, cy - r*0.3, r*0.04, 0, Math.PI*2);
411	  ctx.fill();
412	
413	  foodSprite = c;
414	  return c;
415	}
416	
417	// -------------------- PARTICLE SYSTEM --------------------
418	class Particle {
419	  constructor(w, h) {
420	    this.reset(w, h, true);
421	  }
422	  reset(w, h, initial) {
423	    this.x = Math.random() * w;
424	    this.y = initial ? Math.random() * h : h + 8;
425	    this.vx = (Math.random() - 0.5) * 0.35;
426	    this.vy = -(Math.random() * 0.5 + 0.15);
427	    this.size = Math.random() * 2.2 + 0.6;
428	    this.opacity = Math.random() * 0.55 + 0.15;
429	    this.decay = Math.random() * 0.003 + 0.001;
430	    this.color = Math.random() < 0.55 ? '0,240,255' : '255,0,255';
431	  }
432	  update(w, h) {
433	    this.x += this.vx;
434	    this.y += this.vy;
435	    this.opacity -= this.decay;
436	    if (this.opacity <= 0 || this.y < -10 || this.x < -10 || this.x > w + 10) {
437	      this.reset(w, h, false);
438	    }
439	  }
440	  draw(ctx) {
441	    ctx.fillStyle = `rgba(${this.color},${this.opacity})`;
442	    ctx.shadowColor = `rgba(${this.color},${this.opacity * 0.7})`;
443	    ctx.shadowBlur = this.size * 2.5;
444	    ctx.beginPath();
445	    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
446	    ctx.fill();
447	    ctx.shadowBlur = 0;
448	  }
449	}
450	
451	let particles = [];
452	
453	function initParticles(w, h) {
454	  particles = [];
455	  for (let i = 0; i < CONFIG.PARTICLE_MAX; i++) {
456	    particles.push(new Particle(w, h));
457	  }
458	}
459	
460	function updateParticles(w, h) {
461	  for (const p of particles) p.update(w, h);
462	}
463	
464	function drawParticles(ctx) {
465	  for (const p of particles) p.draw(ctx);
466	}
467	
468	// -------------------- GAME STATE --------------------
469	let gridW, gridH, cellSize;
470	let canvasW, canvasH;
471	let snake, food, direction, nextDirection;
472	let score, foodsEaten;
473	let gameState = 'start';  // 'start' | 'playing' | 'over'
474	let currentSpeed;
475	let lastTickTime = 0;
476	let shakeUntil = 0;
477	let eatEffects = [];       // {x, y, t, maxT}
478	let highScore = 0;
479	
480	// Offscreen canvas for grid background caching
481	let gridCache = null;
482	
483	function loadHighScore() {
484	  try {
485	    const v = localStorage.getItem('cyberSnake_high');
486	    highScore = v ? parseInt(v, 10) : 0;
487	  } catch { highScore = 0; }
488	}
489	
490	function saveHighScore() {
491	  try { localStorage.setItem('cyberSnake_high', highScore.toString()); } catch {}
492	}
493	
494	// -------------------- LAYOUT CALC --------------------
495	function calcLayout() {
496	  const vw = window.innerWidth;
497	  const vh = window.innerHeight;
498	  const padX = vw < 400 ? 12 : 20;
499	  const padTop = 90;  // room for score bar
500	  const padBot = vw < 400 ? 50 : 64;
501	
502	  const availW = vw - padX * 2;
503	  const availH = vh - padTop - padBot;
504	
505	  cellSize = Math.floor(Math.min(availW, availH) / CONFIG.GRID_TARGET);
506	  if (cellSize < CONFIG.MIN_CELL) cellSize = CONFIG.MIN_CELL;
507	
508	  gridW = Math.floor(availW / cellSize);
509	  gridH = Math.floor(availH / cellSize);
510	
511	  canvasW = gridW * cellSize;
512	  canvasH = gridH * cellSize;
513	
514	  gameCanvas.style.width  = canvasW + 'px';
515	  gameCanvas.style.height = canvasH + 'px';
516	  gameCanvas.width  = Math.floor(canvasW * Math.min(window.devicePixelRatio || 1, 2));
517	  gameCanvas.height = Math.floor(canvasH * Math.min(window.devicePixelRatio || 1, 2));
518	  gCtx.setTransform(1, 0, 0, 1, 0, 0);
519	  gCtx.scale(gameCanvas.width / canvasW, gameCanvas.height / canvasH);
520	
521	  // Center game canvas
522	  const left = (vw - canvasW) / 2;
523	  const top  = padTop + (availH - canvasH) / 2;
524	  gameCanvas.style.left = left + 'px';
525	  gameCanvas.style.top  = top + 'px';
526	
527	  // Particle canvas full screen
528	  particleCanvas.width  = Math.floor(vw * Math.min(window.devicePixelRatio || 1, 2));
529	  particleCanvas.height = Math.floor(vh * Math.min(window.devicePixelRatio || 1, 2));
530	  particleCanvas.style.width  = vw + 'px';
531	  particleCanvas.style.height = vh + 'px';
532	  pCtx.setTransform(1,0,0,1,0,0);
533	  pCtx.scale(particleCanvas.width / vw, particleCanvas.height / vh);
534	
535	  // Recreate food sprite for new cell size
536	  createFoodSprite(cellSize);
537	  // Invalidate grid cache
538	  gridCache = null;
539	  // Re-init particles if needed
540	  if (particles.length === 0) initParticles(vw, vh);
541	}
542	
543	// -------------------- GRID CACHE --------------------
544	function buildGridCache() {
545	  if (gridCache) return;
546	  const c = document.createElement('canvas');
547	  c.width = canvasW; c.height = canvasH;
548	  const ctx = c.getContext('2d');
549	
550	  ctx.strokeStyle = 'rgba(0,240,255,0.045)';
551	  ctx.lineWidth = 0.5;
552	  for (let x = 0; x <= gridW; x++) {
553	    ctx.beginPath();
554	    ctx.moveTo(x * cellSize, 0);
555	    ctx.lineTo(x * cellSize, canvasH);
556	    ctx.stroke();
557	  }
558	  for (let y = 0; y <= gridH; y++) {
559	    ctx.beginPath();
560	    ctx.moveTo(0, y * cellSize);
561	    ctx.lineTo(canvasW, y * cellSize);
562	    ctx.stroke();
563	  }
564	  // Corner accents
565	  const acc = cellSize * 0.5;
566	  ctx.strokeStyle = 'rgba(0,240,255,0.25)';
567	  ctx.lineWidth = 1.2;
568	  drawCornerAccent(ctx, 0, 0, acc, 'tl');
569	  drawCornerAccent(ctx, canvasW, 0, acc, 'tr');
570	  drawCornerAccent(ctx, 0, canvasH, acc, 'bl');
571	  drawCornerAccent(ctx, canvasW, canvasH, acc, 'br');
572	
573	  gridCache = c;
574	}
575	
576	function drawCornerAccent(ctx, x, y, len, dir) {
577	  ctx.beginPath();
578	  if (dir === 'tl') { ctx.moveTo(x,y+len); ctx.lineTo(x,y); ctx.lineTo(x+len,y); }
579	  if (dir === 'tr') { ctx.moveTo(x-len,y); ctx.lineTo(x,y); ctx.lineTo(x,y+len); }
580	  if (dir === 'bl') { ctx.moveTo(x,y-len); ctx.lineTo(x,y); ctx.lineTo(x+len,y); }
581	  if (dir === 'br') { ctx.moveTo(x-len,y); ctx.lineTo(x,y); ctx.lineTo(x,y-len); }
582	  ctx.stroke();
583	}
