704	  }
705	
706	  if (score > highScore) {
707	    highScore = score;
708	    saveHighScore();
709	  }
710	
711	  finalScore.textContent = score;
712	  finalHigh.textContent = highScore;
713	  scoreBar.classList.add('hidden');
714	  overPanel.classList.remove('hidden');
