723	// -------------------- RENDER --------------------
724	function renderGame(time) {
725	  const ctx = gCtx;
726	  const w = canvasW, h = canvasH;
727	
728	  // Clear
729	  ctx.clearRect(0, 0, w, h);
730	
731	  // Background
732	  ctx.fillStyle = 'rgba(5,5,16,0.92)';
733	  ctx.fillRect(0, 0, w, h);
734	
735	  // Grid
736	  buildGridCache();
737	  ctx.drawImage(gridCache, 0, 0);
738	
739	  // Glow border
740	  ctx.strokeStyle = 'rgba(0,240,255,0.22)';
741	  ctx.lineWidth = 1.5;
742	  ctx.shadowColor = 'rgba(0,240,255,0.35)';
743	  ctx.shadowBlur = 10;
744	  ctx.strokeRect(0.5, 0.5, w - 1, h - 1);
745	  ctx.shadowBlur = 0;
746	
747	  // Eat effects
748	  for (let i = eatEffects.length - 1; i >= 0; i--) {
749	    const ef = eatEffects[i];
750	    ef.t += 16;
751	    const progress = ef.t / ef.maxT;
752	    if (progress >= 1) { eatEffects.splice(i, 1); continue; }
753	
754	    const cx = ef.x * cellSize + cellSize / 2;
755	    const cy = ef.y * cellSize + cellSize / 2;
756	    const radius = cellSize * (1 + progress * 1.8);
757	    const alpha = 1 - progress;
758	
759	    ctx.strokeStyle = `rgba(255,170,0,${alpha * 0.7})`;
760	    ctx.lineWidth = 2;
761	    ctx.shadowColor = `rgba(255,170,0,${alpha * 0.6})`;
762	    ctx.shadowBlur = 10;
763	    ctx.beginPath();
764	    ctx.arc(cx, cy, radius, 0, Math.PI * 2);
765	    ctx.stroke();
766	
767	    ctx.strokeStyle = `rgba(255,255,255,${alpha * 0.35})`;
768	    ctx.lineWidth = 1;
769	    ctx.shadowColor = 'transparent';
770	    ctx.shadowBlur = 0;
771	    ctx.beginPath();
772	    ctx.arc(cx, cy, radius * 0.6, 0, Math.PI * 2);
773	    ctx.stroke();
774	  }
775	  ctx.shadowBlur = 0;
776	  ctx.lineWidth = 1;
777	
778	  // ---- DRAW FOOD ----
779	  if (food && foodSprite) {
780	    const fx = food.x * cellSize;
781	    const fy = food.y * cellSize;
782	
783	    // Outer glow
784	    ctx.shadowColor = 'rgba(255,140,20,0.55)';
785	    ctx.shadowBlur = cellSize * 0.55;
786	    ctx.drawImage(foodSprite, fx, fy, cellSize, cellSize);
787	    ctx.shadowBlur = 0;
788	
789	    // Pulse ring
790	    const pulse = Math.sin(time * 0.004) * 0.18 + 0.22;
791	    ctx.strokeStyle = `rgba(255,170,40,${pulse})`;
792	    ctx.lineWidth = 1.3;
793	    ctx.beginPath();
794	    const fcx = fx + cellSize/2, fcy = fy + cellSize/2;
795	    ctx.arc(fcx, fcy, cellSize * 0.55, 0, Math.PI * 2);
796	    ctx.stroke();
797	  }
798	
799	  // ---- DRAW SNAKE ----
800	  const shaking = time < shakeUntil;
801	  const shakeAmt = shaking ? Math.max(0, (shakeUntil - time) / CONFIG.SHAKE_MS) * cellSize * 0.28 : 0;
802	  const shakeX = shaking ? (Math.random() - 0.5) * shakeAmt * 2 : 0;
803	  const shakeY = shaking ? (Math.random() - 0.5) * shakeAmt * 2 : 0;
804	
805	  // Body segments (tail to neck)
806	  for (let i = snake.length - 1; i >= 0; i--) {
807	    const seg = snake[i];
808	    const sx = seg.x * cellSize;
809	    const sy = seg.y * cellSize;
810	    const pad = cellSize * 0.12;
811	    const segSize = cellSize - pad * 2;
812	
813	    // Fade from head to tail
814	    const alpha = 1 - (i / Math.max(snake.length, 1)) * 0.55;
815	    const r = Math.floor(0 * alpha);
816	    const g = Math.floor(240 * alpha);
817	    const b = Math.floor(255 * alpha);
818	
819	    ctx.fillStyle = `rgb(${r},${g},${b})`;
820	    ctx.shadowColor = `rgba(0,240,255,${alpha * 0.7})`;
821	    ctx.shadowBlur = CONFIG.GLOW_BLUR * alpha;
822	
823	    const rx = sx + pad + (i === 0 ? shakeX : 0);
824	    const ry = sy + pad + (i === 0 ? shakeY : 0);
825	
826	    ctx.beginPath();
827	    ctx.roundRect(rx, ry, segSize, segSize, cellSize * 0.28);
828	    ctx.fill();
829	
830	    // Inner bright spot
831	    ctx.fillStyle = `rgba(180,255,255,${alpha * 0.5})`;
832	    ctx.shadowBlur = 0;
833	    ctx.beginPath();
834	    ctx.roundRect(rx + segSize*0.2, ry + segSize*0.15, segSize*0.35, segSize*0.3, cellSize*0.12);
835	    ctx.fill();
836	  }
837	  ctx.shadowBlur = 0;
838	
839	  // ---- DRAW HEAD IMAGE ----
840	  const head = snake[0];
841	  const hx = head.x * cellSize + shakeX;
842	  const hy = head.y * cellSize + shakeY;
843	  const hc = cellSize / 2;
844	  const imgPad = cellSize * 0.06;
845	
846	  if (currentHeadImg && currentHeadImg.complete && currentHeadImg.naturalWidth > 0) {
847	    ctx.save();
848	    ctx.beginPath();
849	    ctx.arc(hx + hc, hy + hc, hc - imgPad, 0, Math.PI * 2);
850	    ctx.clip();
851	
852	    // Rotation based on direction
853	    ctx.translate(hx + hc, hy + hc);
854	    const angles = { right: 0, down: Math.PI/2, left: Math.PI, up: -Math.PI/2 };
855	    ctx.rotate(angles[direction] || 0);
856	    ctx.drawImage(currentHeadImg, -hc + imgPad, -hc + imgPad, cellSize - imgPad*2, cellSize - imgPad*2);
857	    ctx.restore();
858	
859	    // Neon ring around head
860	    ctx.strokeStyle = 'rgba(255,0,255,0.7)';
861	    ctx.lineWidth = 2;
862	    ctx.shadowColor = 'rgba(255,0,255,0.8)';
863	    ctx.shadowBlur = 10;
864	    ctx.beginPath();
865	    ctx.arc(hx + hc, hy + hc, hc - imgPad, 0, Math.PI * 2);
866	    ctx.stroke();
867	    ctx.shadowBlur = 0;
868	  } else {
869	    // Fallback: neon triangle head
870	    ctx.fillStyle = '#ff00ff';
871	    ctx.shadowColor = 'rgba(255,0,255,0.8)';
872	    ctx.shadowBlur = 14;
873	    ctx.beginPath();
874	    const angles = { right: 0, down: Math.PI/2, left: Math.PI, up: -Math.PI/2 };
875	    const a = angles[direction] || 0;
876	    ctx.save();
877	    ctx.translate(hx + hc, hy + hc);
878	    ctx.rotate(a);
879	    ctx.moveTo(hc - 2, 0);
880	    ctx.lineTo(-hc + 4, -hc + 4);
881	    ctx.lineTo(-hc + 4, hc - 4);
882	    ctx.closePath();
883	    ctx.fill();
884	    ctx.restore();
885	    ctx.shadowBlur = 0;
886	  }
887	}
