927	function handleTouchStart(e) {
928	  if (gameState === 'start') return; // let buttons handle it
929	  const t = e.touches[0];
930	  touchStartX = t.clientX;
931	  touchStartY = t.clientY;
932	}
933	
934	function handleTouchEnd(e) {
935	  if (gameState !== 'playing') return;
936	  const t = e.changedTouches[0];
937	  const dx = t.clientX - touchStartX;
938	  const dy = t.clientY - touchStartY;
939	  const absDx = Math.abs(dx);
940	  const absDy = Math.abs(dy);
941	
942	  if (Math.max(absDx, absDy) < CONFIG.SWIPE_MIN) return; // too small
943	
944	  if (absDx > absDy) {
945	    nextDirection = dx > 0 ? 'right' : 'left';
946	  } else {
947	    nextDirection = dy > 0 ? 'down' : 'up';
948	  }
949	}
950	
951	function handleKeyDown(e) {
952	  if (gameState !== 'playing') return;
953	  const map = {
954	    ArrowRight: 'right', ArrowLeft: 'left',
955	    ArrowUp: 'up', ArrowDown: 'down',
956	    w: 'up', a: 'left', s: 'down', d: 'right',
957	    W: 'up', A: 'left', S: 'down', D: 'right',
958	  };
959	  const dir = map[e.key];
960	  if (dir) {
961	    e.preventDefault();
962	    nextDirection = dir;
963	  }
964	}
