352	  // Main body
353	  ctx.beginPath();
354	  ctx.arc(cx, cy - r*0.05, r*0.72, 0, Math.PI*2);
355	  ctx.fill();
356	
357	  ctx.shadowColor = 'transparent';
358	  ctx.shadowBlur = 0;
359	  ctx.shadowOffsetY = 0;
360	
361	  // Top swirl — left bump
