365	  ctx.fill();
366	  ctx.fillStyle = '#b8845e';
367	  ctx.beginPath();
368	  ctx.arc(cx - r*0.32, cy - r*0.55, r*0.2, 0, Math.PI*2);
369	  ctx.fill();
370	
371	  // Top swirl — right bump
372	  ctx.fillStyle = '#9a6d44';
373	  ctx.beginPath();
374	  ctx.arc(cx + r*0.34, cy - r*0.5, r*0.3, 0, Math.PI*2);
375	  ctx.fill();
376	  ctx.fillStyle = '#b28055';
377	  ctx.beginPath();
378	  ctx.arc(cx + r*0.34, cy - r*0.53, r*0.22, 0, Math.PI*2);
