417	// -------------------- PARTICLE SYSTEM --------------------
418	class Particle {
419	  constructor(w, h) {
420	    this.reset(w, h, true);
421	  }
422	  reset(w, h, initial) {
423	    this.x = Math.random() * w;
424	    this.y = initial ? Math.random() * h : h + 8;
425	    this.vx = (Math.random() - 0.5) * 0.35;
426	    this.vy = -(Math.random() * 0.5 + 0.15);
427	    this.size = Math.random() * 2.2 + 0.6;
428	    this.opacity = Math.random() * 0.55 + 0.15;
429	    this.decay = Math.random() * 0.003 + 0.001;
430	    this.color = Math.random() < 0.55 ? '0,240,255' : '255,0,255';
431	  }
432	  update(w, h) {
433	    this.x += this.vx;
434	    this.y += this.vy;
435	    this.opacity -= this.decay;
436	    if (this.opacity <= 0 || this.y < -10 || this.x < -10 || this.x > w + 10) {
437	      this.reset(w, h, false);
438	    }
439	  }
440	  draw(ctx) {
441	    ctx.fillStyle = `rgba(${this.color},${this.opacity})`;
442	    ctx.shadowColor = `rgba(${this.color},${this.opacity * 0.7})`;
443	    ctx.shadowBlur = this.size * 2.5;
444	    ctx.beginPath();
445	    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
446	    ctx.fill();
447	    ctx.shadowBlur = 0;
448	  }
449	}
