494	// -------------------- LAYOUT CALC --------------------
495	function calcLayout() {
496	  const vw = window.innerWidth;
497	  const vh = window.innerHeight;
498	  const padX = vw < 400 ? 12 : 20;
499	  const padTop = 90;  // room for score bar
500	  const padBot = vw < 400 ? 50 : 64;
501	
502	  const availW = vw - padX * 2;
503	  const availH = vh - padTop - padBot;
504	
505	  cellSize = Math.floor(Math.min(availW, availH) / CONFIG.GRID_TARGET);
506	  if (cellSize < CONFIG.MIN_CELL) cellSize = CONFIG.MIN_CELL;
507	
508	  gridW = Math.floor(availW / cellSize);
509	  gridH = Math.floor(availH / cellSize);
510	
511	  canvasW = gridW * cellSize;
512	  canvasH = gridH * cellSize;
513	
514	  gameCanvas.style.width  = canvasW + 'px';
515	  gameCanvas.style.height = canvasH + 'px';
516	  gameCanvas.width  = Math.floor(canvasW * Math.min(window.devicePixelRatio || 1, 2));
517	  gameCanvas.height = Math.floor(canvasH * Math.min(window.devicePixelRatio || 1, 2));
518	  gCtx.setTransform(1, 0, 0, 1, 0, 0);
519	  gCtx.scale(gameCanvas.width / canvasW, gameCanvas.height / canvasH);
520	
521	  // Center game canvas
522	  const left = (vw - canvasW) / 2;
523	  const top  = padTop + (availH - canvasH) / 2;
524	  gameCanvas.style.left = left + 'px';
525	  gameCanvas.style.top  = top + 'px';
