585	// -------------------- GAME INIT --------------------
586	function initGame() {
587	  const midX = Math.floor(gridW / 2);
588	  const midY = Math.floor(gridH / 2);
589	
590	  snake = [];
591	  for (let i = 0; i < CONFIG.INITIAL_LEN; i++) {
592	    snake.push({ x: midX - i, y: midY });
593	  }
594	  direction = 'right';
595	  nextDirection = 'right';
596	  score = 0;
597	  foodsEaten = 0;
598	  currentSpeed = CONFIG.BASE_SPEED;
599	  lastTickTime = 0;
600	  shakeUntil = 0;
601	  eatEffects = [];
602	
603	  // Reset head image queue
604	  headQueue = [...headImages];
605	  if (headQueue.length > 0) {
606	    currentHeadImg = headQueue[0];
607	    avatarThumb.src = currentHeadImg.src;
608	  }
609	
610	  placeFood();
611	  updateScoreUI();
612	}
613	
614	function placeFood() {
615	  const occupied = new Set(snake.map(s => `${s.x},${s.y}`));
616	  const free = [];
617	  for (let x = 0; x < gridW; x++) {
618	    for (let y = 0; y < gridH; y++) {
619	      if (!occupied.has(`${x},${y}`)) free.push({ x, y });
620	    }
621	  }
622	  if (free.length === 0) {
623	    // Snake fills entire board — win condition
624	    endGame();
625	    return;
626	  }
627	  food = free[Math.floor(Math.random() * free.length)];
628	}
629	
630	// -------------------- GAME LOOP --------------------
631	function tick() {
632	  if (gameState !== 'playing') return;
633	
634	  // Apply queued direction
635	  if (
636	    (nextDirection === 'right' && direction !== 'left') ||
637	    (nextDirection === 'left'  && direction !== 'right') ||
638	    (nextDirection === 'up'    && direction !== 'down') ||
639	    (nextDirection === 'down'  && direction !== 'up')
640	  ) {
641	    direction = nextDirection;
642	  }
643	
644	  // New head position
645	  const head = snake[0];
646	  const newHead = { x: head.x, y: head.y };
647	  if (direction === 'right') newHead.x++;
648	  if (direction === 'left')  newHead.x--;
649	  if (direction === 'down')  newHead.y++;
650	  if (direction === 'up')    newHead.y--;
651	
652	  // Wall collision
653	  if (newHead.x < 0 || newHead.x >= gridW || newHead.y < 0 || newHead.y >= gridH) {
654	    endGame();
655	    return;
656	  }
657	
658	  // Self collision (check against all segments except tail, since tail will move)
659	  const willGrow = (newHead.x === food.x && newHead.y === food.y);
660	  const checkLen = willGrow ? snake.length : snake.length - 1;
661	  for (let i = 0; i < checkLen; i++) {
662	    if (snake[i].x === newHead.x && snake[i].y === newHead.y) {
663	      endGame();
664	      return;
665	    }
666	  }
667	
668	  // Move snake
669	  snake.unshift(newHead);
670	
671	  if (willGrow) {
672	    // Eat food
673	    foodsEaten++;
674	    score += 10;
675	    currentSpeed = Math.max(CONFIG.MIN_SPEED, CONFIG.BASE_SPEED - foodsEaten * CONFIG.SPEED_STEP);
676	    shakeUntil = performance.now() + CONFIG.SHAKE_MS;
677	    eatEffects.push({
678	      x: food.x, y: food.y,
679	      t: 0, maxT: 380,
680	    });
681	
682	    // Avatar switch every N foods
683	    if (foodsEaten % CONFIG.AVATAR_EVERY === 0) {
684	      cycleHeadImage();
685	    }
686	
687	    // Vibration
688	    if (navigator.vibrate) {
689	      try { navigator.vibrate(40); } catch {}
690	    }
691	
692	    placeFood();
693	    updateScoreUI();
694	  } else {
695	    snake.pop(); // remove tail
696	  }
697	}
