699	function endGame() {
700	  gameState = 'over';
701	  // Death vibration
702	  if (navigator.vibrate) {
703	    try { navigator.vibrate([30, 50, 30, 50, 60]); } catch {}
704	  }
705	
706	  if (score > highScore) {
707	    highScore = score;
708	    saveHighScore();
709	  }
710	
711	  finalScore.textContent = score;
712	  finalHigh.textContent = highScore;
713	  scoreBar.classList.add('hidden');
714	  overPanel.classList.remove('hidden');
715	  swipeHint.style.opacity = '0';
716	}
