889	// -------------------- MAIN LOOP --------------------
890	function gameLoop(time) {
891	  requestAnimationFrame(gameLoop);
892	
893	  // Particle update + render (every frame)
894	  const pw = window.innerWidth, ph = window.innerHeight;
895	  pCtx.clearRect(0, 0, pw, ph);
896	  updateParticles(pw, ph);
897	  drawParticles(pCtx);
898	
899	  // Game tick (fixed timestep)
900	  if (gameState === 'playing' && time - lastTickTime >= currentSpeed) {
901	    tick();
902	    lastTickTime = time;
903	  }
904	
905	  // Render game
906	  if (gameState === 'playing' || gameState === 'over') {
907	    renderGame(time);
908	  } else {
909	    // Draw placeholder grid on start screen
910	    buildGridCache();
911	    gCtx.clearRect(0, 0, canvasW, canvasH);
912	    gCtx.fillStyle = 'rgba(5,5,16,0.92)';
913	    gCtx.fillRect(0, 0, canvasW, canvasH);
914	    gCtx.drawImage(gridCache, 0, 0);
915	    gCtx.strokeStyle = 'rgba(0,240,255,0.22)';
916	    gCtx.lineWidth = 1.5;
917	    gCtx.shadowColor = 'rgba(0,240,255,0.35)';
918	    gCtx.shadowBlur = 10;
919	    gCtx.strokeRect(0.5, 0.5, canvasW - 1, canvasH - 1);
920	    gCtx.shadowBlur = 0;
921	  }
922	}
