967	gameCanvas.addEventListener('touchstart', (e) => { e.preventDefault(); handleTouchStart(e); }, { passive: false });
968	gameCanvas.addEventListener('touchend', (e) => { e.preventDefault(); handleTouchEnd(e); }, { passive: false });
969	gameCanvas.addEventListener('touchmove', (e) => e.preventDefault(), { passive: false });
